340→/**
341→ * Get the current indentation of the line containing the [ASTNode]. By default, this indentation starts with a newline (\n) character.
342→ */
343→public fun ASTNode.indent(includeNewline: Boolean = true): String =
344→    leaves(forward = false)
345→        .firstOrNull { it.isWhiteSpaceWithNewline() }
346→        ?.text
347→        ?.substringAfterLast('\n')
348→        .orEmpty() // Fallback if node is not preceded by any newline character
349→        .applyIf(includeNewline) { prefixIfNot("\n") }
