import com.pinterest.ktlint.rule.engine.core.api.ElementType
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.INDENT_SIZE_PROPERTY
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement
import org.junit.jupiter.api.Test

/**
 * Test that format automatically reruns when autocorrectable errors are found
 */
class FormatRerunTest {

    /**
     * Rule that emits autocorrectable errors on each pass.
     * On first pass, emits "foo1" -> "foo2"
     * On second pass, emits "foo2" -> "foo3"
     * On third pass, emits "foo3" -> "foo4"
     * After 3 passes, no more errors (max reruns reached)
     */
    private class MultiPassAutocorrectRule : Rule(
        ruleId = MULTI_PASS_RULE_ID,
        about = About(),
    ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (node.elementType == ElementType.REGULAR_STRING_PART) {
                when (node.text) {
                    "foo1" -> {
                        emit(node.startOffset, "Replace foo1 with foo2", true)
                        if (autoCorrect) {
                            (node as LeafElement).rawReplaceWithText("foo2")
                        }
                    }
                    "foo2" -> {
                        emit(node.startOffset, "Replace foo2 with foo3", true)
                        if (autoCorrect) {
                            (node as LeafElement).rawReplaceWithText("foo3")
                        }
                    }
                    "foo3" -> {
                        emit(node.startOffset, "Replace foo3 with foo4", true)
                        if (autoCorrect) {
                            (node as LeafElement).rawReplaceWithText("foo4")
                        }
                    }
                    "foo4" -> {
                        // Final state, no more autocorrections
                    }
                }
            }
        }

        companion object {
            val MULTI_PASS_RULE_ID = RuleId("test:multi-pass")
        }
    }

    @Test
    fun `Given that format finds autocorrectable errors then rerun formatting until no more autocorrectable errors found`() {
        val initialCode = """
            val x = "foo1"
        """.trimIndent()

        val callbacks = mutableListOf<CallbackResult>()
        val formattedCode =
            KtLintRuleEngine(
                ruleProviders = setOf(RuleProvider { MultiPassAutocorrectRule() }),
            ).format(Code.fromSnippet(initialCode)) { e, corrected ->
                callbacks.add(
                    CallbackResult(
                        line = e.line,
                        col = e.col,
                        ruleId = e.ruleId,
                        detail = e.detail,
                        canBeAutoCorrected = e.canBeAutoCorrected,
                        corrected = corrected,
                    ),
                )
            }

        // After max 3 reruns, we should reach foo4 (which is fully corrected)
        assertThat(formattedCode).isEqualTo(
            """
            val x = "foo4"
            """.trimIndent(),
        )

